import { test, expect } from '@playwright/test';

test.describe('Filter Functionality', () => {

  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await page.waitForSelector('[data-testid="prompt-card"]');
    console.log('[SETUP] Page loaded, prompt cards visible');
  });

  test.describe('Category Filter', () => {
    test('selecting category filters prompts correctly', async ({ page }) => {
      // Get initial count
      const initialCount = await page.locator('[data-testid="prompt-card"]').count();
      console.log(\`[BEFORE] Total prompts: \${initialCount}\`);

      // Click debugging category
      const debuggingBtn = page.locator('button:has-text("debugging")');
      await debuggingBtn.click();

      // Verify aria-pressed state
      await expect(debuggingBtn).toHaveAttribute('aria-pressed', 'true');
      console.log('[CHECK] Category button aria-pressed=true');

      // Wait for filter to apply
      await page.waitForTimeout(100);

      // Get filtered count
      const filteredCount = await page.locator('[data-testid="prompt-card"]').count();
      console.log(\`[AFTER] Filtered prompts: \${filteredCount}\`);

      // Verify filtering happened
      expect(filteredCount).toBeLessThan(initialCount);

      // Verify all visible cards are in the debugging category
      const categoryBadges = page.locator('[data-testid="prompt-card"] .badge:has-text("debugging")');
      const badgeCount = await categoryBadges.count();
      expect(badgeCount).toBe(filteredCount);
      console.log(\`[PASS] All \${filteredCount} cards show debugging category\`);
    });

    test('clicking All returns to unfiltered view', async ({ page }) => {
      // Apply a filter first
      await page.click('button:has-text("testing")');
      const filteredCount = await page.locator('[data-testid="prompt-card"]').count();
      console.log(\`[FILTER] Testing category: \${filteredCount} prompts\`);

      // Click All
      await page.click('button:has-text("All")');
      await page.waitForTimeout(100);

      const allCount = await page.locator('[data-testid="prompt-card"]').count();
      console.log(\`[RESULT] All prompts restored: \${allCount}\`);

      expect(allCount).toBeGreaterThan(filteredCount);
    });

    test('only one category can be active at a time', async ({ page }) => {
      // Click debugging
      await page.click('button:has-text("debugging")');
      await expect(page.locator('button:has-text("debugging")')).toHaveAttribute('aria-pressed', 'true');

      // Click testing
      await page.click('button:has-text("testing")');

      // Verify debugging is now not pressed
      await expect(page.locator('button:has-text("debugging")')).toHaveAttribute('aria-pressed', 'false');
      await expect(page.locator('button:has-text("testing")')).toHaveAttribute('aria-pressed', 'true');
      console.log('[PASS] Only one category active at a time');
    });
  });

  test.describe('Tag Filter', () => {
    test('multiple tags can be selected simultaneously', async ({ page }) => {
      // Select first tag
      const firstTag = page.locator('[role="group"][aria-labelledby="tag-filter-label"] button').first();
      const firstTagText = await firstTag.textContent();
      await firstTag.click();
      console.log(\`[TAG 1] Selected: \${firstTagText}\`);

      // Select second tag
      const secondTag = page.locator('[role="group"][aria-labelledby="tag-filter-label"] button').nth(1);
      const secondTagText = await secondTag.textContent();
      await secondTag.click();
      console.log(\`[TAG 2] Selected: \${secondTagText}\`);

      // Verify both are pressed
      await expect(firstTag).toHaveAttribute('aria-pressed', 'true');
      await expect(secondTag).toHaveAttribute('aria-pressed', 'true');
      console.log('[PASS] Multiple tags selected');
    });

    test('clear tags button removes all tag selections', async ({ page }) => {
      // Select some tags
      await page.locator('[role="group"][aria-labelledby="tag-filter-label"] button').first().click();
      await page.locator('[role="group"][aria-labelledby="tag-filter-label"] button').nth(1).click();

      // Find and click clear button
      const clearBtn = page.locator('button:has-text("Clear")').filter({ hasText: /\(\d+\)/ });
      await clearBtn.click();
      console.log('[ACTION] Clicked Clear tags button');

      // Verify no tags are pressed
      const pressedTags = page.locator('[role="group"][aria-labelledby="tag-filter-label"] button[aria-pressed="true"]');
      const pressedCount = await pressedTags.count();
      expect(pressedCount).toBe(0);
      console.log('[PASS] All tags cleared');
    });
  });

  test.describe('Search Filter', () => {
    test('search debounces input correctly', async ({ page }) => {
      const searchInput = page.locator('input[aria-label="Search prompts"]');

      // Type quickly
      const startTime = Date.now();
      await searchInput.type('test', { delay: 50 });
      console.log(\`[INPUT] Typed 'test' in \${Date.now() - startTime}ms\`);

      // Results should not update immediately
      await page.waitForTimeout(100);

      // Wait for debounce (300ms)
      await page.waitForTimeout(350);
      const endTime = Date.now();
      console.log(\`[DEBOUNCE] Filter applied after \${endTime - startTime}ms\`);

      // Verify results updated
      const resultHeader = page.locator('h2:has-text("test")');
      await expect(resultHeader).toBeVisible();
      console.log('[PASS] Search debounced correctly');
    });

    test('empty search shows all prompts', async ({ page }) => {
      const searchInput = page.locator('input[aria-label="Search prompts"]');

      // Search something
      await searchInput.fill('testing');
      await page.waitForTimeout(400);
      const filteredCount = await page.locator('[data-testid="prompt-card"]').count();

      // Clear search
      await searchInput.fill('');
      await page.waitForTimeout(400);
      const allCount = await page.locator('[data-testid="prompt-card"]').count();

      expect(allCount).toBeGreaterThanOrEqual(filteredCount);
      console.log(\`[PASS] Empty search: \${allCount} prompts (was \${filteredCount})\`);
    });

    test('no results state displays correctly', async ({ page }) => {
      const searchInput = page.locator('input[aria-label="Search prompts"]');

      await searchInput.fill('xyznonexistentprompt123');
      await page.waitForTimeout(400);

      const noResults = page.locator('text=No prompts found');
      await expect(noResults).toBeVisible();
      console.log('[PASS] No results state displayed');
    });
  });

  test.describe('Combined Filters', () => {
    test('category + tags filter together', async ({ page }) => {
      // Apply category
      await page.click('button:has-text("testing")');
      await page.waitForTimeout(100);
      const categoryCount = await page.locator('[data-testid="prompt-card"]').count();
      console.log(\`[CATEGORY] testing: \${categoryCount} prompts\`);

      // Apply tag
      const firstTag = page.locator('[role="group"][aria-labelledby="tag-filter-label"] button').first();
      await firstTag.click();
      await page.waitForTimeout(100);
      const combinedCount = await page.locator('[data-testid="prompt-card"]').count();
      console.log(\`[COMBINED] category + tag: \${combinedCount} prompts\`);

      expect(combinedCount).toBeLessThanOrEqual(categoryCount);
      console.log('[PASS] Combined filters work correctly');
    });

    test('clearing one filter keeps others active', async ({ page }) => {
      // Apply category and tag
      await page.click('button:has-text("testing")');
      const firstTag = page.locator('[role="group"][aria-labelledby="tag-filter-label"] button').first();
      await firstTag.click();
      await page.waitForTimeout(100);

      // Clear category
      await page.click('button:has-text("All")');
      await page.waitForTimeout(100);

      // Verify tag is still active
      await expect(firstTag).toHaveAttribute('aria-pressed', 'true');
      console.log('[PASS] Tag filter persists after category clear');
    });
  });

  test.describe('Filter Chips (after implementation)', () => {
    test.skip('active filters show as removable chips', async ({ page }) => {
      // TODO: Enable after wi4g is implemented
      await page.click('button:has-text("testing")');

      const chip = page.locator('[data-testid="filter-chip"]:has-text("testing")');
      await expect(chip).toBeVisible();

      // Click X on chip
      await chip.locator('button[aria-label*="Remove"]').click();

      // Verify filter removed
      await expect(page.locator('button:has-text("testing")')).toHaveAttribute('aria-pressed', 'false');
      console.log('[PASS] Filter chip removed filter');
    });
  });

  test.describe('Performance', () => {
    test('filter operations complete within 200ms', async ({ page }) => {
      const startTime = Date.now();

      await page.click('button:has-text("testing")');
      await page.waitForSelector('[data-testid="prompt-card"]');

      const duration = Date.now() - startTime;
      console.log(\`[PERF] Filter operation took \${duration}ms\`);

      expect(duration).toBeLessThan(200);
      console.log('[PASS] Filter performance acceptable');
    });
  });

  test.describe('Accessibility', () => {
    test('all filter buttons are keyboard accessible', async ({ page }) => {
      // Tab to category filter
      await page.keyboard.press('Tab');
      await page.keyboard.press('Tab');
      await page.keyboard.press('Tab');

      // Find focused element
      const focused = page.locator(':focus');
      const role = await focused.getAttribute('role');
      console.log(\`[FOCUS] Focused element role: \${role}\`);

      // Press Enter to activate
      await page.keyboard.press('Enter');

      // Verify something was activated
      const pressed = page.locator('button[aria-pressed="true"]');
      expect(await pressed.count()).toBeGreaterThan(0);
      console.log('[PASS] Keyboard activation works');
    });
  });
});
